gsap.utils.toArray(".product").forEach(product => {
    gsap.from(product, {
        y: 80,
        opacity: 0,
        duration: 1,
        scrollTrigger: {
            trigger: product,
            start: "top 80%",
            end: "bottom 20%",
            toggleActions: "play none none reverse"
        }
    });
});
